function generatePage(page) {
  let sectionsHtml = '';
  for (const section of page.sections) {
    if (!section.heading && !section.text) continue;
    sectionsHtml += `\n      <div class="page-section animate-on-scroll">\n`;
    if (section.heading) sectionsHtml += `        <h2>${section.heading}</h2>\n`;
    if (section.text) sectionsHtml += `        <p>${section.text}</p>\n`;
    if (section.items) {
      sectionsHtml += `        <ul class="page-list">\n`;
      for (const item of section.items) {
        sectionsHtml += `          <li>${item}</li>\n`;
      }
      sectionsHtml += `        </ul>\n`;
    }
    if (section.stats) {
      sectionsHtml += `        <div class="page-stats">\n`;
      for (const stat of section.stats) {
        sectionsHtml += `          <div class="page-stat"><span class="page-stat__value">${stat.value}</span><span class="page-stat__label">${stat.label}</span></div>\n`;
      }
      sectionsHtml += `        </div>\n`;
      if (section.heading === 'Proven Results') {
        sectionsHtml += `        <p style="font-size: 14px; color: rgba(255,255,255,0.5); margin-top: 16px; text-align: center;">We only onboard 5 new AI-managed clients per month to ensure flawless execution.</p>\n`;
      }
    }
    sectionsHtml += `      </div>\n`;
  }

  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${page.title} | Intelligent iT</title>
  <meta name="description" content="${page.subtitle}">
  <link rel="preconnect" href="https://fonts.googleapis.com">
  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
  <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap" rel="stylesheet">
  <link rel="stylesheet" href="../styles.css">
  <link rel="stylesheet" href="pages.css">
  <link rel="icon" type="image/png" sizes="32x32" href="../assets/favicon-32.png">
  <link rel="icon" type="image/png" sizes="16x16" href="../assets/favicon-16.png">
  <!-- HubSpot Tracking Code -->
  <script type="text/javascript" id="hs-script-loader" async defer src="//js.hs-scripts.com/242795522.js"></script>
</head>
<body>
  <header class="header" id="site-header"></header>

  <section class="page-hero">
    <div class="page-hero__bg"></div>
    <div class="container page-hero__inner">
      <span class="page-hero__breadcrumb"><a href="../index.html">Home</a> / ${page.category === 'Industries' ? '<a href="industries.html">' + page.category + '</a>' : '<span style="color: rgba(255,255,255,0.7);">' + page.category + '</span>'} / ${page.title}</span>
      <h1>${page.hero}</h1>
      <p>${page.subtitle}</p>
      <a href="headquarters.html?contact=true" class="btn btn--teal btn--lg">Book a Free Consultation</a>
    </div>
  </section>

  <main class="page-content">
    <div class="container">
${sectionsHtml}
      <div class="page-section" style="margin-top: 48px; padding-top: 32px; border-top: 1px solid rgba(255,255,255,0.06);">
        <p style="font-size: 12px; color: #6b6f80; line-height: 1.7;">Industry context: The average cost of a data breach reached $4.88M in 2024 (IBM Cost of a Data Breach Report, 2024). Mid-market companies lose an average of $5,600 per minute of IT downtime (Gartner). 68% of breaches involve a human element (Verizon 2024 Data Breach Investigations Report). All Intelligent iT performance metrics reflect our internal SLA tracking and client data.</p>
      </div>

      <div class="page-cta">
        <h2>Ready to get started?</h2>
        <p>Book a free IT strategy session and see how Intelligent iT can help your organization.</p>
        <a href="headquarters.html?contact=true" class="btn btn--teal btn--lg">Contact Us Today</a>
      </div>
    </div>
  </main>

  <footer class="footer" id="site-footer"></footer>

  <script src="template.js"></script>
</body>
</html>`;
}

// Pages with custom content — NEVER overwrite these
const skipFiles = [
  'case-studies.html', 'guides.html', 'resource-library.html',
  'blog.html', 'webinars.html', 'overview-video.html',
  'careers.html', 'servicetiers.html', 'headquarters.html',
  'leadership.html', 'it-assessments.html', 'about.html',
  'why-clients-choose-us.html', 'privacy.html', 'terms.html',
  'form-success.html'
];

// Generate all pages
const pagesDir = path.join(__dirname);
let count = 0;
for (const page of pages) {
  if (skipFiles.includes(page.file)) continue;
  const html = generatePage(page);
  fs.writeFileSync(path.join(pagesDir, page.file), html, 'utf8');
  count++;
}
console.log(`Generated ${count} pages.`);
